		case ID_BTN_CANCEL:
		case IDCANCEL:
			EndDialog(hDlg, TRUE);	      /* Exits the dialog box	     */
			return TRUE;

		default:
			break;
			}
        break;
		}

    return (FALSE);			/* Didn't process a message    */
}


